    wwv_flow_api.g_varchar2_table(532) := '9 '||wwv_flow.LF||
'Fecha en que se entiende pagado el impuesto}{\rtlch\fcs1 \ai\af1 \ltrch\fcs0 \cs23\i\f1\insrsid11';
    wwv_flow_api.g_varchar2_table(533) := '348159\charrsid10370899 . Se tendr\''e1 como fecha de pago del impuesto respecto de cada contribuyent';
    wwv_flow_api.g_varchar2_table(534) := 'e, '||wwv_flow.LF||
'aquella en que los valores imputables hayan ingresados a las oficinas de los impuestos o a los B';
    wwv_flow_api.g_varchar2_table(535) := 'ancos autorizados, a\''fan en los casos en que se hayan recibido inicialmente como simples dep\''f3'||wwv_flow.LF||
'si';
    wwv_flow_api.g_varchar2_table(536) := 'tos, buenas cuentas, retenciones en la fuente, o que resulten como saldos a su favor por cualquier c';
    wwv_flow_api.g_varchar2_table(537) := 'oncepto\''85\''94}{\rtlch\fcs1 \af1 \ltrch\fcs0 \f1\insrsid11348159\charrsid10370899 '||wwv_flow.LF||
